import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"Настройка среды разработки","description":"Пошаговое руководство по настройке среды разработки для создания модов с помощью Fabric.","frontmatter":{"title":"Настройка среды разработки","description":"Пошаговое руководство по настройке среды разработки для создания модов с помощью Fabric.","authors":["IMB11","andrew6rant","SolidBlock-cn","modmuss50","daomephsta","liach","telepathicgrunt","2xsaiko","natanfudge","mkpoli","falseresync","asiekierka"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"ru_ru/1.21.1/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.1/translated/ru_ru/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1761424914000}`);var o={name:`ru_ru/1.21.1/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Настройка среды разработки <a class="header-anchor" href="#h1" aria-label="Permalink to “Настройка среды разработки”">​</a></h1><p>Для начала разработки модов с использованием Fabric вам нужно настроить среду разработки в IntelliJ IDEA.</p><h2 id="installing-jdk-21" tabindex="-1">Установка JDK 21 <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “Установка JDK 21”">​</a></h2><p>Для разработки модов для Minecraft 1.21.1 вам потребуется JDK 21.</p><p>Если вам нужна помощь в установке Java, вы можете обратиться к различным руководствам по установке Java в <a href="./../../players/index">разделе руководств для игроков</a>.</p><h2 id="installing-intellij-idea" tabindex="-1">Установка IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Установка IntelliJ IDEA”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Вы также можете использовать и другие IDE, например Eclipse или Visual Studio Code, но большинство страниц в этой документации предполагают что вы используете IntelliJ IDEA, если вы используете другую IDE, обратитесь к документации по ней.</p></div><p>Если у вас не установлена IntelliJ IDEA, вы можете её установить на <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">официальном сайте</a> - следуйте шагам установки для вашей операционной системы.</p><p>Community edition IntelliJ IDEA бесплатна и имеет открытый исходный код, и также она рекомендуемая версия для модинга с Fabric.</p><p>Возможно, вам придется прокрутить страницу вниз, чтобы найти ссылку на загрузку Community edition, она выглядит следующим образом:</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="Подсказка для загрузки Community Edition" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Установка плагинов IDEA <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Установка плагинов IDEA”">​</a></h2><p>Хотя эти плагины не являются необходимыми, они могут сделать ваш процесс моддинга с Fabric более лёгким, вам следует подумать об их установкой.</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Плагин Minecraft Development предоставляет поддержку моддинга с Fabric, и это самый важный плагин для установки.</p><p>Вы можете установить его открытием IntelliJ IDEA, а затем перейти по адресу <code>File &gt; Settings &gt; Plugins &gt; Marketplace Tab</code> и найти <code>Minecraft Development</code> в поисковой строке, и затем нажать кнопку <code>Install</code>.</p><p>Альтернативный вариант: вы можете установить его на <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">странице плагина</a> и затем установите его по адресу <code>File &gt; Settings &gt; Plugins &gt; Install Plugin From Disk</code>.</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};